def gen(rng, size):
    n = max(1, min(size, 40))
    edges = []
    for u in range(n):
        for v in range(u + 1, n):
            if rng.random() < 0.3 and len(edges) < 300:
                edges.append([u, v, rng.randrange(1, 11)])
    k = rng.randrange(0, 8)
    t = rng.randrange(1, 60)
    return [n, edges, k, t]

