class Solution:
    def maxWeight(self, n, edges, k, t):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
        best = [-1]
        import sys
        sys.setrecursionlimit(10000)
        def dfs(node, e, s):
            if s >= t:
                return
            if e == k:
                if s > best[0]:
                    best[0] = s
                return
            for (v, w) in adj[node]:
                dfs(v, e + 1, s + w)
        if k == 0:
            return 0 if 0 < t else -1
        for start in range(n):
            dfs(start, 0, 0)
        return best[0]

