class Solution:
    def maxWeight(self, n, edges, k, t):
        adj = [[] for _ in range(n)]
        for u, v, w in edges:
            adj[u].append((v, w))
        if k == 0:
            return 0 if 0 < t else -1
        cur = [set([0]) for _ in range(n)]
        for _ in range(k):
            nxt = [set() for _ in range(n)]
            for u in range(n):
                cu = cur[u]
                if not cu:
                    continue
                for (v, w) in adj[u]:
                    nv = nxt[v]
                    for s in cu:
                        ns = s + w
                        if ns < t:
                            nv.add(ns)
            cur = nxt
        best = -1
        for node in range(n):
            for s in cur[node]:
                if s > best:
                    best = s
        return best

