var maxWeight = function(n, edges, k, t) {
    const adj = Array.from({length: n}, () => []);
    for (const [u, v, w] of edges) adj[u].push([v, w]);
    if (k === 0) return 0 < t ? 0 : -1;
    let cur = Array.from({length: n}, () => new Set([0]));
    for (let e = 0; e < k; e++) {
        const nxt = Array.from({length: n}, () => new Set());
        for (let u = 0; u < n; u++) {
            if (cur[u].size === 0) continue;
            for (const [v, w] of adj[u]) {
                const nv = nxt[v];
                for (const s of cur[u]) {
                    const ns = s + w;
                    if (ns < t) nv.add(ns);
                }
            }
        }
        cur = nxt;
    }
    let best = -1;
    for (let node = 0; node < n; node++) {
        for (const s of cur[node]) if (s > best) best = s;
    }
    return best;
};
